const payload = $json.body && typeof $json.body === 'object'
  ? $json.body
  : $json;

function pick(...values) {
  return values.find((v) => {
    if (v === undefined || v === null) return false;
    return String(v).trim() !== '';
  });
}

function slug(value) {
  return String(value || 'requirement')
    .trim()
    .replace(/^REQ_/i, '')
    .replace(/\.[^.]+$/, '')
    .replace(/\s+/g, '_')
    .replace(/[^A-Za-z0-9가-힣_-]+/g, '_')
    .replace(/_+/g, '_')
    .replace(/^_+|_+$/g, '');
}

function timestamp() {
  const d = new Date();
  const yy = String(d.getFullYear()).slice(-2);
  const mm = String(d.getMonth() + 1).padStart(2, '0');
  const dd = String(d.getDate()).padStart(2, '0');
  const hh = String(d.getHours()).padStart(2, '0');
  const mi = String(d.getMinutes()).padStart(2, '0');
  const ss = String(d.getSeconds()).padStart(2, '0');
  return `${yy}${mm}${dd}_${hh}${mi}${ss}`;
}

const DEFAULT_VERCEL_BASE_URL = 'https://howardchoi-nsus-pocax.vercel.app';

const keyword = slug(
  pick(
    payload.requirementKeyword,
    payload.requirement_keyword,
    payload.keyword,
    payload.title,
    payload.requirementId,
    'manual'
  )
);

const ts = timestamp();

const requirementId = pick(
  payload.requirementId,
  payload.requirement_id,
  `REQ_${keyword}_${ts}`
);

const sourceText = pick(
  payload.sourceText,
  payload.requirementText,
  payload.requirement_text,
  payload.content,
  payload.text,
  ''
);

if (!String(sourceText).trim()) {
  throw new Error('sourceText 또는 requirementText 값이 없습니다.');
}

const sourceType = pick(payload.sourceType, payload.source_type, 'DIRECT');

const sourceLabel = pick(
  payload.sourceLabel,
  payload.source_label,
  sourceType === 'DIRECT' ? '직접등록' : sourceType
);

return [
  {
    json: {
      action: 'requirement_save',

      requirementKeyword: keyword,
      requirementId,

      sourceType,
      sourceLabel,
      sourceDetail: pick(payload.sourceDetail, payload.source_detail, ''),

      sourceText: String(sourceText).trim(),

      storageType: 'vercel_blob',

      vercelBaseUrl: String(
        pick(
          payload.vercelBaseUrl,
          payload.vercel_base_url,
          payload.baseUrl,
          DEFAULT_VERCEL_BASE_URL
        )
      ).replace(/\/+$/, ''),

      sourceDir: pick(
        payload.sourceDir,
        payload.githubSourceDir,
        payload.github_source_dir,
        'source'
      ),

      reqDir: pick(
        payload.reqDir,
        payload.githubReqDir,
        payload.github_req_dir,
        'req'
      ),

      requestedBy: pick(payload.requestedBy, payload.requested_by, 'web'),
      receivedAt: new Date().toISOString()
    }
  }
];

const input = $json;
function toBase64(value) { return Buffer.from(value, 'utf8').toString('base64').replace(/\r?\n|\r/g, ''); }
const sourceDir = (input.githubSourceDir || 'source').replace(/^\/+|\/+$/g, '');
const sourceFileName = `${input.requirementId}.txt`;
const sourceFilePath = `${sourceDir}/${sourceFileName}`;
const metaBlock = [
  `source_type: ${input.sourceType}`,
  `source_label: ${input.sourceLabel}`,
  input.sourceDetail ? `source_detail: ${input.sourceDetail}` : '',
  `created_at: ${new Date().toISOString()}`,
  ''
].filter(Boolean).join('\n');
const sourceBody = `${metaBlock}\n${input.sourceText}`;
return [{ json: {
  ...input,
  sourceFileName,
  sourceFilePath,
  sourceBody,
  sourceRequestBody: {
    message: `Save source requirement: ${sourceFileName}`,
    content: toBase64(sourceBody),
    branch: input.githubBranch || 'main'
  }
}}];

const input = $('Prepare Source File').item.json;
function toBase64(value) { return Buffer.from(value, 'utf8').toString('base64').replace(/\r?\n|\r/g, ''); }
const reqDir = (input.githubReqDir || 'req').replace(/^\/+|\/+$/g, '');
const reqFileName = `${input.requirementId}.md`;
const requirementFilePath = `${reqDir}/${reqFileName}`;
const reqMarkdown = `---
requirement_id: ${input.requirementId}
source_type: ${input.sourceType}
source_label: ${input.sourceLabel}
source_detail: ${String(input.sourceDetail || '').replace(/\n/g, ' ')}
source_file: ${input.sourceFilePath}
created_at: ${new Date().toISOString()}
status: registered
agent: agent1_requirement_save
---

# 요구사항

${input.sourceText.trim()}
`;
return [{ json: {
  ...input,
  reqFileName,
  requirementFilePath,
  reqMarkdown,
  requirementRequestBody: {
    message: `Save normalized requirement: ${reqFileName}`,
    content: toBase64(reqMarkdown),
    branch: input.githubBranch || 'main'
  }
}}];

const input = $('Prepare Requirement File').item.json;
return [{ json: {
  success: true,
  action: 'requirement_save',
  message: '요구사항이 Git Repository에 저장되었습니다.',
  requirementId: input.requirementId,
  sourceFilePath: input.sourceFilePath,
  requirementFilePath: input.requirementFilePath,
  githubOwner: input.githubOwner,
  githubRepo: input.githubRepo,
  githubBranch: input.githubBranch,
  createdAt: new Date().toISOString()
}}];

const payload = $json.body && typeof $json.body === 'object'
  ? $json.body
  : $json;

function pick(...values) {
  return values.find((value) => {
    if (value === undefined || value === null) return false;
    return String(value).trim() !== '';
  });
}

function timestamp() {
  const d = new Date();
  const yy = String(d.getFullYear()).slice(-2);
  const mm = String(d.getMonth() + 1).padStart(2, '0');
  const dd = String(d.getDate()).padStart(2, '0');
  const hh = String(d.getHours()).padStart(2, '0');
  const mi = String(d.getMinutes()).padStart(2, '0');
  const ss = String(d.getSeconds()).padStart(2, '0');
  return `${yy}${mm}${dd}_${hh}${mi}${ss}`;
}

function normalizePath(path) {
  return String(path || '')
    .trim()
    .replace(/^\/+/, '');
}

function normalizeDir(dir, fallback) {
  return String(dir || fallback)
    .trim()
    .replace(/^\/+|\/+$/g, '');
}

function makeTitleFromPaths(paths, fallback) {
  if (!paths.length) return fallback;

  const firstName = String(paths[0])
    .split('/')
    .pop()
    .replace(/\.[^.]+$/, '')
    .replace(/^REQ_/i, '');

  const suffix = paths.length > 1 ? `_외_${paths.length - 1}건` : '';

  return `${firstName}${suffix}`;
}

const paths =
  payload.requirementFilePaths ||
  payload.requirementFiles ||
  payload.reqFilePaths ||
  payload.requirements ||
  [];

if (!Array.isArray(paths) || !paths.length) {
  throw new Error('requirementFilePaths 배열이 필요합니다.');
}

const normalizedPaths = paths.map(normalizePath).filter(Boolean);

if (!normalizedPaths.length) {
  throw new Error('유효한 요구사항 파일 경로가 없습니다.');
}

const ts = timestamp();

const requirementSetId = pick(
  payload.requirementSetId,
  `REQ_SET_${ts}`
);

const requestId = pick(
  payload.requestId,
  requirementSetId
);

const vercelBaseUrl = String(
  pick(
    payload.vercelBaseUrl,
    payload.vercel_base_url,
    payload.baseUrl,
    'https://howardchoi-nsus-pocax.vercel.app'
  )
).replace(/\/+$/, '');

const promptFilePath = normalizePath(
  pick(
    payload.promptFilePath,
    payload.promptTemplate,
    'prompts/prd-template-v1.md'
  )
);

const outputDir = normalizeDir(
  pick(payload.outputDir, payload.githubOutputDir),
  'prd'
);

const mapDir = normalizeDir(
  pick(payload.mapDir, payload.githubMapDir),
  'maps'
);

const logDir = normalizeDir(
  pick(payload.logDir, payload.githubLogDir),
  'logs'
);

const documentTitle = pick(
  payload.documentTitle,
  payload.docTitle,
  makeTitleFromPaths(normalizedPaths, requirementSetId)
);

return [
  {
    json: {
      action: 'agent1_prd_generate',
      storageType: 'vercel_blob',

      vercelBaseUrl,

      requestId,
      requirementSetId,
      requirementFilePaths: normalizedPaths,
      promptFilePath,

      model: pick(payload.model, 'gpt-4o-mini'),
      documentTitle,

      outputDir,
      mapDir,
      logDir,

      requestedBy: pick(payload.requestedBy, 'web'),
      timestamp: ts,
      estimatedSeconds: Number(payload.estimatedSeconds || 0) || null,
      receivedAt: new Date().toISOString()
    }
  }
];

const input = $json;

const baseUrl = String(
  input.vercelBaseUrl || 'https://howardchoi-nsus-pocax.vercel.app'
).replace(/\/+$/, '');

async function readBlobText(path) {
  const cleanPath = String(path || '').replace(/^\/+/, '');

  if (!cleanPath) {
    throw new Error('읽을 파일 경로가 비어 있습니다.');
  }

  const url = `${baseUrl}/api/blob-file?path=${encodeURIComponent(cleanPath)}`;

  const data = await this.helpers.httpRequest({
    method: 'GET',
    url,
    headers: {
      Accept: 'application/json'
    },
    json: true
  });

  if (!data || data.success === false) {
    throw new Error(data?.message || `${cleanPath} 파일 조회 실패`);
  }

  const content = data.content || data.text || '';

  if (!String(content).trim()) {
    throw new Error(`${cleanPath} 파일 내용이 비어 있습니다.`);
  }

  return content;
}

const requirementDocs = [];

for (const path of input.requirementFilePaths || []) {
  const text = await readBlobText.call(this, path);

  requirementDocs.push({
    path,
    text
  });
}

if (!requirementDocs.length) {
  throw new Error('읽어온 요구사항 문서가 없습니다.');
}

const promptText = await readBlobText.call(this, input.promptFilePath);

return [
  {
    json: {
      ...input,
      requirementDocs,
      promptText
    }
  }
];

const input = $json;
function normalizeText(text) {
  return String(text || '').replace(/\r\n/g, '\n').replace(/\n{3,}/g, '\n\n').replace(/[ \t]+$/gm, '').trim();
}
const mergedRequirements = input.requirementDocs
  .map((doc, idx) => `## 요구사항 ${idx + 1}: ${doc.path}\n\n${normalizeText(doc.text)}`)
  .join('\n\n---\n\n');
const outputDir = (input.outputDir || input.githubOutputDir || 'prd').replace(/^\/+|\/+$/g, '');
const mapDir = (input.mapDir || input.githubMapDir || 'maps').replace(/^\/+|\/+$/g, '');
const logDir = (input.logDir || input.githubLogDir || 'logs').replace(/^\/+|\/+$/g, '');
const titleSlug = String(input.documentTitle || input.requirementSetId).replace(/[^A-Za-z0-9가-힣_-]+/g, '_').replace(/^_+|_+$/g, '');
const prdFileName = `PRD_${titleSlug}_${input.timestamp}.md`;
const mapFileName = `MAP_${titleSlug}_${input.timestamp}.json`;
const logFileName = `LOG_${titleSlug}_${input.timestamp}.json`;
const prdFilePath = `${outputDir}/${prdFileName}`;
const mapFilePath = `${mapDir}/${mapFileName}`;
const logFilePath = `${logDir}/${logFileName}`;
const llmInput = `${normalizeText(input.promptText)}

---

# 입력 요구사항 묶음

${mergedRequirements}

---

# 생성 요청

위 요구사항 묶음을 기반으로 하나의 PRD 문서를 작성한다.

출력 조건:
- Markdown 형식으로 작성
- PRD 문서 본문만 출력
- 선택된 요구사항 파일 경로를 출처로 명시
- 불명확한 내용은 "확인 필요"로 표시
- 임의로 기능, 정책, 일정, 범위를 확정하지 말 것
- 중복 요구사항은 정리하고, 충돌 항목은 "충돌/확인 필요"로 분리할 것
- 개발자, 디자이너, QA가 바로 이해할 수 있도록 기능 요구사항과 예외 케이스를 구조화할 것`;
return [{ json: {
  ...input,
  mergedRequirements,
  prdFileName,
  mapFileName,
  logFileName,
  prdFilePath,
  mapFilePath,
  logFilePath,
  llmInput,
  preprocess: {
    requirementCount: input.requirementDocs.length,
    promptCharCount: normalizeText(input.promptText).length,
    requirementCharCount: mergedRequirements.length,
    llmInputCharCount: llmInput.length,
    normalized: true,
    duplicateCheck: 'instruction_based',
    conflictCheck: 'instruction_based'
  }
}}];

const input = $('Pre-process Selected Requirements').item.json;
const llm = $json;
function extractText(value) {
  if (!value) return '';
  if (typeof value === 'string') return value;
  if (Array.isArray(value)) return value.map(extractText).filter(Boolean).join('\n');
  if (typeof value === 'object') {
    if (typeof value.text === 'string') return value.text;
    if (typeof value.output_text === 'string') return value.output_text;
    if (typeof value.content === 'string') return value.content;
    if (Array.isArray(value.content)) return extractText(value.content);
    if (Array.isArray(value.output)) return extractText(value.output);
    if (value.message?.content) return extractText(value.message.content);
    if (value.choices) return extractText(value.choices);
  }
  return '';
}
function toBase64(value) { return Buffer.from(value, 'utf8').toString('base64').replace(/\r?\n|\r/g, ''); }
const prdMarkdown = extractText(llm).trim();
if (!prdMarkdown) throw new Error('LLM 출력에서 PRD Markdown을 찾지 못했습니다. Generate PRD 노드 응답 구조를 확인하세요.');
const mapping = {
  requestId: input.requestId,
  requirementSetId: input.requirementSetId,
  requirementFilePaths: input.requirementFilePaths,
  promptFilePath: input.promptFilePath,
  prdFilePath: input.prdFilePath,
  mapFilePath: input.mapFilePath,
  logFilePath: input.logFilePath,
  agent: 'agent1_prd_generate',
  model: input.model || 'gpt-4o-mini',
  status: 'success',
  createdAt: new Date().toISOString(),
  requestedBy: input.requestedBy || 'web'
};
const log = {
  requestId: input.requestId,
  executionId: $execution?.id || null,
  workflowId: $workflow?.id || null,
  workflowName: $workflow?.name || 'AGENT1_PRD_WebIntegrated_v0.4',
  agent: 'agent1_prd_generate',
  requirementSetId: input.requirementSetId,
  requirementFilePaths: input.requirementFilePaths,
  promptFilePath: input.promptFilePath,
  prdFilePath: input.prdFilePath,
  mapFilePath: input.mapFilePath,
  logFilePath: input.logFilePath,
  status: 'success',
  startedAt: input.receivedAt || null,
  endedAt: new Date().toISOString(),
  preprocess: input.preprocess
};
return [{

  json: {

    githubOwner: input.githubOwner,

    githubRepo: input.githubRepo,

    githubBranch: input.githubBranch || 'main',

    requestId: input.requestId,
    requirementSetId: input.requirementSetId,

    requirementFilePaths: input.requirementFilePaths,

    promptFilePath: input.promptFilePath,

    prdFilePath: input.prdFilePath,

    mapFilePath: input.mapFilePath,

    logFilePath: input.logFilePath,

    prdMarkdown,

    mapping,

    log,

    mappingText: JSON.stringify(mapping, null, 2),

    logText: JSON.stringify(log, null, 2),

    prdRequestBody: {

      message: `Add generated PRD: ${input.prdFileName}`,

      content: toBase64(prdMarkdown),

      branch: input.githubBranch || 'main'

    },

    mapRequestBody: {

      message: `Save Req-PRD mapping: ${input.mapFileName}`,

      content: toBase64(JSON.stringify(mapping, null, 2)),

      branch: input.githubBranch || 'main'

    },

    logRequestBody: {

      message: `Save Agent1 execution log: ${input.logFileName}`,

      content: toBase64(JSON.stringify(log, null, 2)),

      branch: input.githubBranch || 'main'

    }

  }

}];

const input = $('Pre-process Selected Requirements').item.json;
const errorPayload = $json || {};
const error = errorPayload.error || errorPayload;
const message = error.message || error.description || errorPayload.message || 'n8n workflow error';
const logDir = String(input.logDir || 'logs').replace(/^\/+|\/+$/g, '');
const id = input.requestId || input.requirementSetId || input.timestamp;
const errorFilePath = `${logDir}/ERR_${id}_${input.timestamp}.json`;
const response = {
  success: false,
  status: 'error',
  step: 'Generate PRD',
  nodeName: 'Generate PRD',
  message,
  requestId: input.requestId,
  requirementSetId: input.requirementSetId,
  requirementFilePaths: input.requirementFilePaths,
  promptFilePath: input.promptFilePath,
  errorFilePath,
  createdAt: new Date().toISOString()
};
return [{ json: {
  ...input,
  status: 'error',
  errorFilePath,
  errorText: JSON.stringify(response, null, 2),
  response
}}];
